<script setup>
import{ref}from'vue';import{Head,Link}from'@inertiajs/vue3';import axios from'axios';
const props=defineProps({email:String,requests:Array});const items=ref([...props.requests]);const newEmail=ref('');const saving=ref(false);const message=ref('');const requestChange=async()=>{saving.value=true;message.value='';try{const r=await axios.post(route('participant-portal.contact.email.request'),{email:newEmail.value});items.value.unshift(r.data.request);message.value=r.data.message;newEmail.value='';}finally{saving.value=false;}};const cancel=async(item)=>{await axios.delete(route('participant-portal.contact.cancel',item.id));item.cancelled_at=new Date().toISOString();};const status=(item)=>item.confirmed_at?'Bestätigt':item.cancelled_at?'Abgebrochen':new Date(item.expires_at)<new Date()?'Abgelaufen':'Bestätigung offen';
</script>
<template><Head title="Kontaktdaten"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-4xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Kontaktdaten und Zugang</h1></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2">Dashboard</Link></header><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">E-Mail-Adresse ändern</h2><p class="mt-1 text-sm text-gray-500">Aktuell: {{ email }}. Die neue Adresse wird erst nach Klick auf den Bestätigungslink übernommen.</p><form class="mt-4 flex gap-3" @submit.prevent="requestChange"><input v-model="newEmail" type="email" required placeholder="Neue E-Mail-Adresse" class="flex-1 rounded border-gray-300"/><button class="rounded bg-zbb px-4 py-2 text-white disabled:opacity-50" :disabled="saving">Bestätigungslink senden</button></form><p v-if="message" class="mt-3 rounded bg-green-50 p-3 text-sm text-green-700">{{ message }}</p></section><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Änderungsverlauf</h2><div class="mt-4 space-y-3"><article v-for="item in items" :key="item.id" class="rounded-xl border p-4"><div class="flex flex-wrap justify-between gap-3"><div><p class="font-semibold">{{ item.old_value }} → {{ item.new_value }}</p><p class="text-xs text-gray-500">Beantragt: {{ new Date(item.created_at).toLocaleString('de-DE') }} · gültig bis {{ new Date(item.expires_at).toLocaleString('de-DE') }}</p></div><span class="rounded-full bg-gray-100 px-3 py-1 text-xs">{{ status(item) }}</span></div><button v-if="!item.confirmed_at&&!item.cancelled_at&&new Date(item.expires_at)>=new Date()" class="mt-3 text-sm text-red-600" @click="cancel(item)">Anfrage abbrechen</button></article><p v-if="!items.length" class="text-sm text-gray-500">Noch keine Änderungen beantragt.</p></div></section></div></main></template>
